import software.amazon.awssdk.auth.credentials.ProfileCredentialsProvider
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model._

object AwsS3Service {

  val region: Region = Region.US_EAST_1
  val credentialsProvider: ProfileCredentialsProvider = ProfileCredentialsProvider.create()

  def main(args: Array[String]): Unit = {
    val s3Client = S3Client.builder()
      .region(region)
      .credentialsProvider(credentialsProvider)
      .build()

    // Example operation: List buckets
    listBuckets(s3Client)

    // Example operation: Upload a file
    uploadFile(s3Client, "my-bucket", "path/to/local/file.txt")

    s3Client.close()
  }

  def listBuckets(s3Client: S3Client): Unit = {
    println("Listing buckets:")
    val response = s3Client.list_buckets(ListBucketsRequest.builder().build())
    for (bucket <- response.buckets()) {
      println(bucket.name())
    }
  }

  def uploadFile(s3Client: S3Client, bucketName: String, filePath: String): Unit = {
    println(s"Uploading $filePath to $bucketName")
    val putObjectRequest = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(filePath.split("/").last)
      .build()

    s3Client.put_object(putObjectRequest, java.nio.file.Paths.get(filePath))
    println("File uploaded successfully")
  }
}